	"github.com/pressly/goose/v3"
)

// MigrateUp runs all pending goose UP migrations embedded in the binary.
func MigrateUp(ctx context.Context, databaseURL string) error {
	slog.Info("migrate: running up migrations")
	start := time.Now()

	db, err := sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("migrate: failed to open db: %w", err)
	}
	defer db.Close() //nolint:errcheck // best-effort close

	goose.SetBaseFS(migrations.FS)
	if err := goose.SetDialect("postgres"); err != nil {
		return fmt.Errorf("migrate: set dialect: %w", err)
	}

	if err := goose.UpContext(ctx, db, "."); err != nil {
		slog.Error("migrate: up failed", "error", err, "duration_ms", time.Since(start).Milliseconds())
		return fmt.Errorf("migrate: up: %w", err)
	}

	slog.Info("migrate: up completed", "duration_ms", time.Since(start).Milliseconds())
	return nil
}

// MigrateDown rolls back the most recent goose migration.
func MigrateDown(ctx context.Context, databaseURL string) error {
	slog.Info("migrate: rolling back last migration")
	start := time.Now()

	db, err := sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("migrate: failed to open db: %w", err)
	}
	defer db.Close() //nolint:errcheck // best-effort close

	goose.SetBaseFS(migrations.FS)
	if err := goose.SetDialect("postgres"); err != nil {
		return fmt.Errorf("migrate: set dialect: %w", err)
	}

	if err := goose.DownContext(ctx, db, "."); err != nil {
		slog.Error("migrate: down failed", "error", err, "duration_ms", time.Since(start).Milliseconds())
		return fmt.Errorf("migrate: down: %w", err)
	}

	slog.Info("migrate: down completed", "duration_ms", time.Since(start).Milliseconds())
	return nil
}

